'use strict';
import React from "react"
import { Link } from 'react-router-dom';

class Evalulation extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
          results: []
        };
    }

        componentDidMount() {
            // get all entities - GET
            fetch(`http://localhost:9000/amioncall`, {
                "method": "GET"
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
              })
              .catch(err => {
                console.log(err);
              });


          }

          render() {
            return (
                <div className="container">
                  <div className="row justify-content-center">
                    <div className="col-md-8">
                      <h1 className="display-4 text-center">Make An API Call in React</h1>


{this.state.results}


                      <form className="d-flex flex-column">
                        <legend className="text-center">Add-Update-Delete Friend</legend>
                        <label htmlFor="name">
                          Friend Name:
                          <input
                            name="name"
                            id="name"
                            type="text"
                            className="form-control"
                            value={this.state.name}
                            onChange={(e) => this.handleChange({ name: e.target.value })}
                            required
                            />
                        </label>
                        <label htmlFor="notes">
                          Friend notes:
                          <input
                            name="notes"
                            id="notes"
                            type="test"
                            className="form-control"
                            value={this.state.notes}
                            onChange={(e) => this.handleChange({ notes: e.target.value })}
                            required
                            />
                        </label>
                        <label htmlFor="id">
                          Friend ID:
                          <input
                            name="id"
                            id="id"
                            type="text"
                            className="form-control"
                            value={this.state.id}
                            onChange={(e) => this.handleChange({ id: e.target.value })}
                            />
                        </label>
                        <button className="btn btn-primary" type='button' onClick={(e) => this.create(e)}>
                          Add
                        </button>
                        <button className="btn btn-info" type='button' onClick={(e) => this.update(e)}>
                            Update
                        </button>
                        <button className="btn btn-danger" type='button' onClick={(e) => this.delete(e)}>
                            Delete
                        </button>
                      </form>
                    </div>
                  </div>
                </div>
            );
          }


  };

  export default Evalulation
